import{_ as s,o as a,i as t,ad as i}from"./chunks/framework.By85nKlP.js";const g=JSON.parse('{"title":"Comparison","description":"csv-pipe versus papaparse, csv-parse, csv-stringify, and fast-csv. A typed, zero-dependency, faster CSV alternative for TypeScript on Node, browsers, Deno, Bun, and edge.","frontmatter":{"description":"csv-pipe versus papaparse, csv-parse, csv-stringify, and fast-csv. A typed, zero-dependency, faster CSV alternative for TypeScript on Node, browsers, Deno, Bun, and edge."},"headers":[],"relativePath":"guide/comparison.md","filePath":"guide/comparison.md","lastUpdated":1782402901000}'),n={name:"guide/comparison.md"};function r(o,e,d,p,h,l){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h1><p>csv-pipe both encodes and parses CSV. It is the fastest of the common libraries at parsing by a wide margin, and the fastest or on par at encoding. The table compares the attributes that differ; throughput is covered on the <a href="./benchmarks">benchmarks page</a>.</p><table tabindex="0"><thead><tr><th></th><th>csv-pipe</th><th>papaparse</th><th>csv-stringify / csv-parse</th><th>fast-csv</th></tr></thead><tbody><tr><td>Direction</td><td>encode + parse</td><td>encode + parse</td><td>encode + parse</td><td>encode + parse</td></tr><tr><td>Columns checked against your type</td><td>Yes</td><td>No</td><td>No</td><td>No</td></tr><tr><td>Runtimes</td><td>Node, browser, Deno, Bun, edge</td><td>Node, browser</td><td>Node, browser</td><td>Node</td></tr><tr><td>Web <code>ReadableStream</code></td><td>Yes</td><td>No</td><td>Partial</td><td>No</td></tr><tr><td>Built-in formula-injection guard</td><td>Yes</td><td>Yes</td><td>Yes</td><td>No</td></tr><tr><td>Runtime dependencies</td><td>None</td><td>None</td><td>None</td><td>A few</td></tr><tr><td>Fastest at parsing (wide margin)</td><td>Yes</td><td>No</td><td>No</td><td>No</td></tr><tr><td>Fastest or on par at encoding</td><td>Yes</td><td>No</td><td>No</td><td>No</td></tr></tbody></table><p>Attributes other than throughput reflect the documented behavior and current published versions of each library (papaparse 5, csv-parse 7, csv-stringify 6, fast-csv 5), and may change between versions; check the current docs of each. csv-pipe returns a Web <code>ReadableStream</code> from the encoder, which suits an HTTP or edge response body. csv-parse 7 has a Web Streams parser (<code>csv-parse/stream</code>), while csv-stringify uses Node streams, so that column is mixed.</p><h2 id="when-to-choose-csv-pipe" tabindex="-1">When to choose csv-pipe <a class="header-anchor" href="#when-to-choose-csv-pipe" aria-label="Permalink to &quot;When to choose csv-pipe&quot;">​</a></h2><ul><li>You write TypeScript and want a typo in a column to fail at compile time.</li><li>Your code runs on the edge, in the browser, or under Deno or Bun, not only Node.</li><li>You stream large files and want a Web <code>ReadableStream</code> for an HTTP body.</li><li>You export untrusted data and want formula injection handled by an option.</li><li>You want one small, fast dependency for both directions.</li></ul><h2 id="when-to-choose-something-else" tabindex="-1">When to choose something else <a class="header-anchor" href="#when-to-choose-something-else" aria-label="Permalink to &quot;When to choose something else&quot;">​</a></h2><ul><li><strong>You need a wider data toolkit</strong> (parsing pipelines, transforms, CSV plus other formats). fast-csv and the <code>csv</code> package cover more ground.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><p><strong>What is a good alternative to papaparse?</strong></p><p>csv-pipe. It encodes and parses like papaparse, adds column names checked against your type at compile time, runs on Deno, Bun, and edge as well as Node and the browser, and parses several times faster. Migration is usually a one-line change.</p><p><strong>What is the fastest CSV parser for Node and TypeScript?</strong></p><p>In the <a href="./benchmarks">benchmarks</a> here, csv-pipe parses several times faster than papaparse, csv-parse, and fast-csv across every dataset tested.</p><p><strong>Is there a typed CSV parser for TypeScript?</strong></p><p>Yes. csv-pipe is written in TypeScript with no <code>any</code> in the public surface, and column names are checked against your record type, so a typo fails at compile time.</p><p><strong>Which CSV library works on Deno, Bun, and edge runtimes?</strong></p><p>csv-pipe. The core imports no <code>fs</code> and no DOM and returns a Web <code>ReadableStream</code>, so one import runs on Node, browsers, Deno, Bun, and edge.</p><p><strong>Does csv-pipe have runtime dependencies?</strong></p><p>No. It ships zero runtime dependencies, at about 2 kB per direction.</p><h2 id="migrating" tabindex="-1">Migrating <a class="header-anchor" href="#migrating" aria-label="Permalink to &quot;Migrating&quot;">​</a></h2><p>The call is usually a one-line change in either direction. For example, from papaparse:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// papaparse</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Papa </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;papaparse&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Papa.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">unparse</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(rows);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Papa.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">parse</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(text, { header: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> });</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// csv-pipe</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { stringify, parse } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;csv-pipe&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">stringify</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(rows);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">parse</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(text);</span></span></code></pre></div><p>See <a href="./migration">Migration</a> for the full option mapping from papaparse, csv-stringify, csv-parse, and fast-csv.</p>`,23)])])}const k=s(n,[["render",r]]);export{g as __pageData,k as default};
